// HasWithdrawal applies the HasEdge predicate on the "withdrawal" edge.
func HasWithdrawal() predicate.CommissionWithdrawalItem {
	return predicate.CommissionWithdrawalItem(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, WithdrawalTable, WithdrawalColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasWithdrawalWith applies the HasEdge predicate on the "withdrawal" edge with a given conditions (other predicates).
func HasWithdrawalWith(preds ...predicate.CommissionWithdrawal) predicate.CommissionWithdrawalItem {
	return predicate.CommissionWithdrawalItem(func(s *sql.Selector) {
		step := newWithdrawalStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

